const raw = $input.first().json.chatInput || '';
const txt = raw.toLowerCase();
let flow = 'new_loan';
if (/payment|missed|overdue|balance|loan.?status|delinquent|servicing|existing.?loan/.test(txt)) {
  flow = 'existing_loan';
} else if (/\baml\b|\bkyc\b|suspicious|\bsar\b|compliance|fraud|risk.?review|regulatory/.test(txt)) {
  flow = 'compliance';
}
const custMatch = raw.match(/\b(\d{4,6})\b/);
const customer_id = custMatch ? custMatch[1] : null;
return [{ json: { flow, customer_id, chatInput: raw } }];

const combined = $input.first().json.combined || '';
const pick = (regex, fallback = 'UNKNOWN') => {
  const match = combined.match(regex);
  return match ? match[1].trim() : fallback;
};
const customerId = pick(/customer_id:\s*([^\n]+)/i, $json.customer_id ? String($json.customer_id) : 'UNKNOWN');
const fullName = pick(/full_name:\s*([^\n]+)/i);
const loanAmount = pick(/loan_amount:\s*([^\n]+)/i);
const creditVerdict = pick(/credit_verdict:\s*([^\n]+)/i);
const paymentVerdict = pick(/payment_verdict:\s*([^\n]+)/i);
const propertyVerdict = pick(/property_verdict:\s*([^\n]+)/i);
const ltvRatio = pick(/ltv_ratio:\s*([^\n]+)/i);
const signals = [];
if (/WEAK|INSUFFICIENT_DATA/i.test(creditVerdict)) signals.push('credit_verdict: ' + creditVerdict);
if (/WEAK|INSUFFICIENT_DATA/i.test(paymentVerdict) || /payment_reliability:\s*High Risk/i.test(combined)) signals.push('payment_verdict: ' + paymentVerdict);
if (/WEAK|INSUFFICIENT_DATA/i.test(propertyVerdict)) signals.push('property_verdict: ' + propertyVerdict);
if (/^UNKNOWN$/i.test(ltvRatio) === false && Number.parseFloat(ltvRatio) >= 90) signals.push('ltv_ratio: ' + ltvRatio);
return [{ json: { text: [
  '==============================',
  'LOAN APPLICATION - FLAGGED FOR HUMAN REVIEW',
  '==============================',
  'Customer:    ' + fullName + ' | ID: ' + customerId,
  'Loan Amount: $' + loanAmount,
  '',
  'RISK SIGNALS DETECTED:',
  ...(signals.length ? signals.map((s) => '  ' + s) : ['  Manual review required based on risk gate trigger']),
  '',
  'AGENT FINDINGS SUMMARY:',
  '  Credit Verdict:   ' + creditVerdict,
  '  Payment Verdict:  ' + paymentVerdict,
  '  Property Verdict: ' + propertyVerdict,
  '  LTV Ratio:        ' + ltvRatio,
  '',
  'ACTION REQUIRED:',
  '  Manual underwriter review is required before any decision is issued.',
  '  Do not approve or decline without senior sign-off.',
  '',
  'Flagged by: Autonomous Risk Gate - Denodo-powered loan assessment pipeline.',
  '=============================='
].join('\n') } }];

const findings = $input.first().json.output || '';
const custMatch  = findings.match(/customer_id:\s*(\d+)/);
const nameMatch  = findings.match(/full_name:\s*([^\n]+)/);
const reasonMatch = findings.match(/sar_reasons:\s*([^\n]+)/);
const reportId = 'SAR-' + Date.now();
return [{ json: { text: [
  '==============================',
  'SUSPICIOUS ACTIVITY REPORT FILED',
  '==============================',
  'Report ID:     ' + reportId,
  'Customer ID:   ' + (custMatch  ? custMatch[1]  : 'UNKNOWN'),
  'Customer Name: ' + (nameMatch  ? nameMatch[1].trim()  : 'UNKNOWN'),
  'SAR Reasons:   ' + (reasonMatch ? reasonMatch[1].trim() : 'See findings'),
  '',
  'Compliance Findings:',
  findings,
  '',
  'IMPORTANT: Do not alert the customer. Escalated to compliance officer.',
  'Timestamp: ' + new Date().toISOString(),
  '=============================='
].join('\n') } }];
